#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
char buf[1<<21],*p1=buf,*p2=buf;
#define rg register
inline int read()
{
	rg int res=0;rg char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Max(rg int x,rg int y){return x>y?x:y;}
inline int Min(rg int x,rg int y){return x<y?x:y;}
inline void Swap(rg int &x,rg int &y){rg int tmp=x;x=y;y=tmp;}
const int N=1e5+10;int n,Col;
struct Graph
{
	int head[N],des[N<<1],nxt[N<<1],cnt;
	inline void ins(rg int x,rg int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
	inline void Init(){memset(head,0,sizeof(head));cnt=0;}
}a;
namespace SegmentTree
{
	int ltag[N<<2],rtag[N<<2],tag[N<<2],sum[N<<2],L,R,Sum;
	bool debug,vis;
	inline void update(rg int k)
	{
		rg int ls=k<<1,rs=ls|1;
		sum[k]=sum[ls]+sum[rs]+(ltag[rs]&&ltag[rs]==rtag[ls]);
		ltag[k]=ltag[ls];rtag[k]=rtag[rs];
	}
	inline void pushdown(rg int k,rg int l,rg int r)
	{
		if(!tag[k])return;rg int mid=(l+r)>>1,ls=k<<1,rs=ls|1,col=tag[k];tag[k]=0;
		ltag[ls]=ltag[rs]=rtag[ls]=rtag[rs]=tag[ls]=tag[rs]=col;sum[ls]=mid-l;sum[rs]=r-mid-1;
//		if(k==2&&l==1&&r==4){printf("\ncaonima %d %d\n\n",l,mid);}
	}
	inline void fxd(rg int ql,rg int qr,rg int col,rg int l=1,rg int r=n,rg int cur=1)
	{
		if(ql<=l&&r<=qr){ltag[cur]=rtag[cur]=tag[cur]=col;sum[cur]=r-l;return;}pushdown(cur,l,r);
		rg int mid=(l+r)>>1;ql<=mid?fxd(ql,qr,col,l,mid,cur<<1):void(0);qr>mid?fxd(ql,qr,col,mid+1,r,cur<<1|1):void(0);update(cur);
	}
	inline void Qry(rg int ql,rg int qr,rg int l=1,rg int r=n,rg int cur=1)
	{
		if(ql<=l&&r<=qr){Sum+=sum[cur];Sum+=(R&&R==ltag[cur]);if(!vis)L=ltag[cur],vis=1;R=rtag[cur];return;}pushdown(cur,l,r);
		rg int mid=(l+r)>>1;ql<=mid?Qry(ql,qr,l,mid,cur<<1):void(0);qr>mid?Qry(ql,qr,mid+1,r,cur<<1|1):void(0);update(cur);
//		if(1){printf("cao? %d %d %d %d %d %d %d %d\n",l,r,cur,sum[cur],ltag[cur],rtag[cur],tag[cur],Sum);}
	}
	inline int qry(rg int ql,rg int qr){R=Sum=0;vis=0;Qry(ql,qr);return Sum;} 
}
using namespace SegmentTree;
namespace TreeCut
{
	int mxs[N],idx[N],dep[N],siz[N],fa[N],top[N],cpt;
	inline void dfs1(rg int u=1,rg int f=0)
	{
		dep[u]=dep[fa[u]=f]+(siz[u]=1);rg int mx=0;
		grep(a,u,i)
		{
			rg int v=a.des[i];if(v==f)continue;
			dfs1(v,u);siz[u]+=siz[v];siz[v]>mx?mx=siz[v],mxs[u]=v:0;
		}
	}
	inline void dfs2(rg int u=1,rg int f=0,rg int tpf=1)
	{
		top[u]=tpf;idx[u]=++cpt;mxs[u]?dfs2(mxs[u],u,tpf):void(0);
		grep(a,u,i){rg int v=a.des[i];if(v^f&&v^mxs[u])dfs2(v,u,v);}
	}
}
using namespace TreeCut;
inline void Fixed(rg int u,rg int v,rg int col)
{
	while(top[u]^top[v])
	{
		dep[top[u]]<dep[top[v]]?Swap(u,v):void(0);
//		printf("fixed %d %d %d\n",idx[u],idx[top[u]],col);
		fxd(idx[top[u]],idx[u],col);u=fa[top[u]];
	}
	dep[u]<dep[v]?Swap(u,v):void(0);
//	printf("fixed %d %d %d\n",idx[v],idx[u],col);
	fxd(idx[v],idx[u],col);
}
inline int Query(rg int u,rg int v)
{
	rg int res=0,ul=0,vl=0;while(top[u]^top[v])
	{
		dep[top[u]]<dep[top[v]]?Swap(u,v),Swap(ul,vl):void(0);
		res+=qry(idx[top[u]],idx[u]);res+=(ul&&ul==R);ul=L;
//		printf("query %d %d %d (%d,%d)(%d,%d)\n",top[u],u,res,ul,vl,L,R);
		u=fa[top[u]];
	}
	dep[u]<dep[v]?Swap(u,v),Swap(ul,vl):void(0);
	res+=qry(idx[v],idx[u]);res+=(vl&&vl==L);res+=(ul&&ul==R);
//	printf("query %d %d %d %d %d %d\n",v,u,res,L,R,vl);
	return res;
}
inline void Init()
{
	a.Init();memset(mxs,0,sizeof(mxs));cpt=Col=0;
	memset(ltag,0,sizeof(ltag));memset(rtag,0,sizeof(rtag));
	memset(tag,0,sizeof(tag));memset(sum,0,sizeof(sum));
}
inline void Solve()
{
	Init();n=read();rg int m=read();
	rep(2,n,i){rg int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	dfs1();dfs2();
//	rep(1,n,i)printf("%d : %d\n",i,idx[i]);
	while(m--)
	{
		rg int opt=read(),u=read(),v=read();
		opt==1?Fixed(u,v,++Col),0:printf("%d\n",Query(u,v));
	}
}
int main()
{
//	freopen("data.txt","r",stdin);
//	freopen("mine.txt","w",stdout);
	int T=read();while(T--)Solve();return 0;
}
